INSERT INTO public.challenges (title, description, category, difficulty, points, flag, hints, hint_costs, is_active) VALUES
('SQL Injection 101', 'A simple login form is vulnerable to SQL injection. Can you bypass authentication?', 'web', 'easy', 50, 'cyberops{sql_1nj3ct10n_b4s1cs}', ARRAY['Think about what happens when you add a single quote', 'Try common SQL injection payloads'], ARRAY[10, 25], true),
('XSS Cookie Stealer', 'Find the reflected XSS vulnerability in the search page and craft a payload to steal the admin cookie.', 'web', 'medium', 150, 'cyberops{r3fl3ct3d_xss_c00k13s}', ARRAY['Look at the search parameter in the URL', 'The application does not sanitize HTML in query params'], ARRAY[15, 30], true),
('JWT Token Forge', 'The application uses JWT for authentication. The secret might be weaker than you think.', 'web', 'hard', 300, 'cyberops{jwt_n0n3_4lg0r1thm_byp4ss}', ARRAY['Check the JWT algorithm', 'What happens with alg: none?'], ARRAY[25, 50], true),
('SSRF to Internal', 'The PDF generator fetches URLs to create documents. Can you reach the internal metadata service?', 'web', 'hard', 350, 'cyberops{ssrf_m3t4d4t4_l34k}', ARRAY['Try localhost or 127.0.0.1', 'Look for cloud metadata endpoints'], ARRAY[30, 60], true),
