('Blind XXE', 'The XML parser seems to accept external entities. Extract the flag file from the server.', 'web', 'insane', 500, 'cyberops{bl1nd_xx3_0ut_0f_b4nd}', ARRAY['Research XML External Entities', 'You may need out-of-band data exfiltration'], ARRAY[40, 80], true),
