('Caesar Cipher', 'Decrypt this message: FLJHURSV{E4v1F_FU1SW0}', 'crypto', 'easy', 50, 'cyberops{b4s1c_cr1pt0}', ARRAY['This is a classic substitution cipher', 'Try shifting each letter by a fixed amount'], ARRAY[10, 20], true),
('Base64 Layers', 'The flag has been encoded multiple times with base64. Decode until you find it: Y3liZXJvcHN7YjRzMzY0XzBuYzNfdHcxYzNfdGhyMWMzfQ==', 'crypto', 'easy', 75, 'cyberops{b4s364_0nc3_tw1c3_thr1c3}', ARRAY['This is base64 encoded', 'Try decoding it multiple times'], ARRAY[10, 20], true),
('RSA Small e', 'Given n=3233, e=3, and ciphertext c=2790, find the plaintext m.', 'crypto', 'medium', 200, 'cyberops{sm4ll_3_4tt4ck_rs4}', ARRAY['With small e, the ciphertext might not wrap around n', 'Try computing the cube root of c'], ARRAY[20, 40], true),
